const CONFIG = {
  webhookSecret: 'd1683be39187b1559a38c8f80293cb0866778d55613596ba45125c6de3abf37b'
};
const input = items[0]?.json || {};
const headers = input.headers || {};
const receivedSecret = headers['x-clinvetia-n8n-secret'] || headers['X-Clinvetia-N8n-Secret'] || '';
if (receivedSecret !== CONFIG.webhookSecret) {
  return [{ json: { reply: 'Moka no está disponible ahora mismo.', state: { intent: 'none', step: 'idle' }, booking: null, shouldDelegate: false } }];
}
const payload = input.body && typeof input.body === 'object' ? input.body : {};
const state = payload.state && typeof payload.state === 'object' ? payload.state : { intent: 'none', step: 'idle' };
const message = typeof payload.message === 'string' ? payload.message.trim() : '';
const locale = payload.locale === 'en' ? 'en' : 'es';
const lower = message.toLowerCase();
const history = Array.isArray(payload.history) ? payload.history.slice(-6) : [];
const shouldDelegate = Boolean(
  payload.sessionToken ||
  payload.bookingToken ||
  state.intent === 'book' ||
  state.intent === 'reschedule' ||
  state.intent === 'cancel' ||
  /(reserv|reserva|demo|cita|agenda|reagend|reprogram|cancel|horario|slot|booking|appointment|reschedule|roi|presupuesto|factura|trabajo)/i.test(lower)
);
const transcript = history.map((item) => `${item.role === 'assistant' ? 'assistant' : 'user'}: ${String(item.content || '').replace(/\s+/g, ' ').trim()}`).join('\n');
const triagePrompt = [
  locale === 'en' ? 'You are Moka, Clinvetia\'s website assistant.' : 'Eres Moka, el asistente web de Clinvetia.',
  locale === 'en' ? 'Respond ONLY with valid JSON using this exact format: {"mode":"answer"|"delegate","reply":"text"}.' : 'Responde SOLO con JSON valido usando este formato exacto: {"mode":"answer"|"delegate","reply":"texto"}.',
  locale === 'en' ? 'Use mode=answer only for greetings, who-is-Clinvetia, what-do-you-do, simple product questions and general guidance.' : 'Usa mode=answer solo para saludos, quien es Clinvetia, que haceis, dudas simples del servicio y orientacion general.',
  locale === 'en' ? 'Use mode=delegate for booking, rescheduling, cancellation, times, availability, ROI, forms, client data, tokens, invoices, jobs, quotes, or if unsure.' : 'Usa mode=delegate para reservas, reagendados, cancelaciones, horarios, disponibilidad, ROI, formularios, datos del cliente, tokens, facturas, trabajos, presupuestos o si tienes dudas.',
  `locale: ${locale}`,
  `message: ${message}`,
  `stateIntent: ${state.intent || 'none'}`,
  `stateStep: ${state.step || 'idle'}`,
  `history:\n${transcript || 'none'}`
].join('\n');
return [{ json: { payload, message, locale, state, history, triagePrompt, shouldDelegate } }];

const current = items[0]?.json || {};
const payload = current.payload && typeof current.payload === 'object' ? current.payload : {};
const state = current.state && typeof current.state === 'object' ? current.state : { intent: 'none', step: 'idle' };
const rawText = typeof current.output_text === 'string'
  ? current.output_text
  : Array.isArray(current.output)
    ? current.output.flatMap((entry) => Array.isArray(entry?.content) ? entry.content : []).map((entry) => entry?.text || '').join('\n')
    : '';
let mode = 'delegate';
let reply = '';
if (rawText) {
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    if (parsed && typeof parsed === 'object') {
      mode = parsed.mode === 'answer' ? 'answer' : 'delegate';
      reply = typeof parsed.reply === 'string' ? parsed.reply.trim() : '';
    }
  } catch {}
}
return [{ json: { payload, state, aiMode: mode, aiReply: reply, shouldDelegate: !(mode === 'answer' && reply) } }];
